import React from "react";

export default function Footer() {
  return (
    <>
      <style>
        {`
          .custom-footer {
            background: linear-gradient(135deg, #000000, #1a1a1a, #0a0a0a);
            padding: 20px 20px;
            margin-top: 0;
            width: 100%;
            border-radius: 0;
            position: relative;
            box-shadow: 0 -5px 30px rgba(0,0,0,0.5);
          }

          .custom-footer::before {
            content: '';
            position: absolute;
            top: 0;
            left: 0;
            right: 0;
            height: 3px;
            background: linear-gradient(90deg, #1877F2, #fd1d1d, #fffc00, #4de8f4, #25d366);
            background-size: 200% 100%;
            animation: gradient 3s ease infinite;
          }

          @keyframes gradient {
            0% {
              background-position: 0% 50%;
            }
            50% {
              background-position: 100% 50%;
            }
            100% {
              background-position: 0% 50%;
            }
          }

          .footer-container {
            display: flex;
            justify-content: space-evenly;
            align-items: center;
            flex-wrap: wrap;
            gap: 30px;
            margin: 0 auto;
            max-width: 600px;
          }

          .footer-container a {
            display: flex;
            justify-content: center;
            align-items: center;
            text-decoration: none;
            transition: 0.3s ease;
            font-size: 3rem;
            color: var(--color);
            flex-shrink: 0;
          }

          .footer-container a:hover {
            transform: translateY(-8px) scale(1.2);
            text-shadow: 0 0 15px var(--color),
                         0 0 30px var(--color),
                         0 0 60px var(--color);
          }

          @media (max-width: 768px) {
            .footer-container a {
              font-size: 2.5rem;
            }

            .footer-container {
              gap: 25px;
              max-width: 500px;
            }

            .custom-footer {
              padding: 15px 15px;
            }
          }

          @media (max-width: 480px) {
            .footer-container a {
              font-size: 2rem;
            }

            .footer-container {
              gap: 20px;
              max-width: 350px;
            }

            .custom-footer {
              padding: 12px 10px;
            }
          }
        `}
      </style>

      <footer className="custom-footer">
        <div className="footer-container">
          <a href="#" style={{ "--color": "#1877F2" }}>
            <i className="fa-brands fa-facebook"></i>
          </a>
          <a href="#" style={{ "--color": "#fd1d1d" }}>
            <i className="fa-brands fa-instagram"></i>
          </a>
          <a href="#" style={{ "--color": "#fffc00" }}>
            <i className="fa-brands fa-snapchat"></i>
          </a>
          <a href="#" style={{ "--color": "#4de8f4" }}>
            <i className="fa-brands fa-tiktok"></i>
          </a>
          <a href="#" style={{ "--color": "#25d366" }}>
            <i className="fa-brands fa-whatsapp"></i>
          </a>
        </div>
      </footer>
    </>
  );
}
